from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetAOVsNode(BaseNode):
    name = "Prism: Get AOVs"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("version", "any")
        self.add_output("aovs", "list")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        version = inputs.get('version')
        if core is None or version is None:
            self.log_error("Need PrismCore and version.")
            return {'aovs': [], 'count': 0}
        try:
            media_module = getattr(core, 'mediaProducts', None) or getattr(core, 'media', None)
            aovs = []
            for attr in ('getAOVsFromVersion', 'getAOVs'):
                if hasattr(media_module, attr):
                    aovs = getattr(media_module, attr)(version) or []
                    break
            self.log_info(f"Found {len(aovs)} AOV(s).")
            return {'aovs': list(aovs), 'count': len(aovs)}
        except Exception as e:
            self.log_error(f"getAOVs failed: {e}")
            return {'aovs': [], 'count': 0}

def register_node():
    return PrismGetAOVsNode
